-- ============================================================
-- food_catalog seed ampliado para app de calorías / nutrición
-- Diseñado para PostgreSQL / Supabase
-- Total filas seed: 2729
--   - genéricas verificadas: 226
--   - variantes de búsqueda / marca: 2503
-- Notas:
--   1) Las filas branded/derivadas se marcan con is_verified = FALSE.
--   2) search_text y aliases ayudan a que búsquedas como "pipas"
--      devuelvan genéricos y marcas (Facundo, Piponazo, Tijuana, etc.).
--   3) El objetivo aquí es maximizar cobertura de búsqueda sin romper
--      tu tabla actual. Puedes seguir usando food_catalog.
-- ============================================================

BEGIN;

CREATE EXTENSION IF NOT EXISTS unaccent;
CREATE EXTENSION IF NOT EXISTS pg_trgm;

ALTER TABLE food_catalog
    ADD COLUMN IF NOT EXISTS slug TEXT,
    ADD COLUMN IF NOT EXISTS aliases TEXT[] DEFAULT ARRAY[]::TEXT[],
    ADD COLUMN IF NOT EXISTS search_text TEXT,
    ADD COLUMN IF NOT EXISTS parent_slug TEXT,
    ADD COLUMN IF NOT EXISTS is_brand_variant BOOLEAN DEFAULT FALSE,
    ADD COLUMN IF NOT EXISTS source_note TEXT,
    ADD COLUMN IF NOT EXISTS popularity_score INTEGER DEFAULT 0;

CREATE OR REPLACE FUNCTION normalize_food_text(input_text TEXT)
RETURNS TEXT
LANGUAGE SQL
STABLE
AS $$
    SELECT trim(regexp_replace(lower(unaccent(coalesce(input_text, ''))), '\s+', ' ', 'g'));
$$;

CREATE OR REPLACE FUNCTION slugify_food_text(input_text TEXT)
RETURNS TEXT
LANGUAGE SQL
STABLE
AS $$
    SELECT regexp_replace(normalize_food_text(input_text), '\s+', '-', 'g');
$$;

-- Backfill mínimo para filas ya existentes en tu tabla
UPDATE food_catalog
SET
    slug = COALESCE(NULLIF(slug, ''), slugify_food_text(concat_ws(' ', coalesce(provider, 'generic'), coalesce(name_es, name)))),
    aliases = COALESCE(aliases, ARRAY[]::TEXT[]),
    parent_slug = COALESCE(parent_slug, NULL),
    is_brand_variant = COALESCE(is_brand_variant, FALSE),
    source_note = COALESCE(source_note, 'existing_row'),
    popularity_score = COALESCE(popularity_score, CASE WHEN provider = 'generic' THEN 90 ELSE 70 END),
    search_text = COALESCE(
        search_text,
        normalize_food_text(
            concat_ws(' ',
                coalesce(name, ''),
                coalesce(name_es, ''),
                coalesce(provider, ''),
                array_to_string(COALESCE(aliases, ARRAY[]::TEXT[]), ' ')
            )
        )
    );

CREATE UNIQUE INDEX IF NOT EXISTS uq_food_catalog_slug ON food_catalog (slug);
CREATE INDEX IF NOT EXISTS idx_food_catalog_provider ON food_catalog (provider);
CREATE INDEX IF NOT EXISTS idx_food_catalog_category ON food_catalog (category);
CREATE INDEX IF NOT EXISTS idx_food_catalog_search_text_trgm
    ON food_catalog USING GIN (search_text gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_food_catalog_name_es_trgm
    ON food_catalog USING GIN (name_es gin_trgm_ops);

CREATE OR REPLACE FUNCTION search_foods(q TEXT, max_results INT DEFAULT 25)
RETURNS TABLE (
    slug TEXT,
    name TEXT,
    name_es TEXT,
    category TEXT,
    provider TEXT,
    kcal_per_100g NUMERIC,
    protein_per_100g NUMERIC,
    carbs_per_100g NUMERIC,
    fat_per_100g NUMERIC,
    fiber_per_100g NUMERIC,
    is_verified BOOLEAN,
    parent_slug TEXT,
    is_brand_variant BOOLEAN,
    popularity_score INTEGER,
    match_score REAL
)
LANGUAGE SQL
STABLE
AS $$
WITH input AS (
    SELECT normalize_food_text(q) AS needle
)
SELECT
    f.slug,
    f.name,
    f.name_es,
    f.category,
    f.provider,
    f.kcal_per_100g,
    f.protein_per_100g,
    f.carbs_per_100g,
    f.fat_per_100g,
    f.fiber_per_100g,
    f.is_verified,
    f.parent_slug,
    f.is_brand_variant,
    f.popularity_score,
    (
        CASE
            WHEN normalize_food_text(f.name_es) = i.needle THEN 150
            WHEN normalize_food_text(f.name) = i.needle THEN 145
            WHEN normalize_food_text(f.provider || ' ' || f.name_es) = i.needle THEN 140
            WHEN EXISTS (
                SELECT 1
                FROM unnest(coalesce(f.aliases, ARRAY[]::TEXT[])) a
                WHERE normalize_food_text(a) = i.needle
            ) THEN 135
            WHEN normalize_food_text(f.name_es) LIKE i.needle || '%' THEN 120
            WHEN f.search_text LIKE '%' || i.needle || '%' THEN 90
            ELSE 0
        END
        + (similarity(f.search_text, i.needle) * 20)
        + CASE WHEN f.provider = 'generic' THEN 25 ELSE 0 END
        + CASE WHEN f.is_verified THEN 5 ELSE 0 END
        + (LEAST(GREATEST(f.popularity_score, 0), 100) * 0.08)
    )::REAL AS match_score
FROM food_catalog f
CROSS JOIN input i
WHERE f.search_text LIKE '%' || i.needle || '%'
   OR similarity(f.search_text, i.needle) > 0.12
ORDER BY
    match_score DESC,
    CASE WHEN f.provider = 'generic' THEN 0 ELSE 1 END,
    f.name_es ASC
LIMIT GREATEST(max_results, 1);
$$;

